const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const force = body.force === true;
let reverifyDays=90;
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const v=(s.items&&s.items[0]&&s.items[0].value)||{}; if(v.reverify_days!=null)reverifyDays=v.reverify_days; }catch(e){}
const cutoffMs = Date.now() - (reverifyDays*86400000);
let contacts=[];
if(Array.isArray(body.ids) && body.ids.length){
  for(const id of body.ids){ try{ const c=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records/'+id,headers:pbH,json:true}); contacts.push(c); }catch(e){} }
} else {
  const filter=body.filter||''; let page=1;
  while(true){ const qs=Object.assign({perPage:500,page,fields:'id,email,verified_at,verification_status,blocklisted'},filter?{filter}:{}); const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs,headers:pbH,json:true}); contacts=contacts.concat(r.items||[]); if(page>=(r.totalPages||1))break; page++; }
}
const seen=new Set();
const settled={verified:1,undeliverable:1,catch_all:1,mx_only:1};
const emails=[]; const map={};
for(const c of contacts){
  if(!c.email||seen.has(c.email)) continue;
  if(c.blocklisted===true) continue;
  const vAt=c.verified_at? new Date(String(c.verified_at).replace(' ','T')).getTime():0;
  if(!force && vAt && vAt>cutoffMs && settled[c.verification_status]) continue;
  const em=String(c.email).trim(); if(!em) continue;
  seen.add(c.email); emails.push(em); map[em.toLowerCase()]=c.id;
}
const MAX=50000; let truncated=0;
if(emails.length>MAX){ truncated=emails.length-MAX; emails.length=MAX; }
const sd=$getWorkflowStaticData('global'); const now=new Date().toISOString();
let jobId='';
try{ const j=await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/job_runs/records',headers:pbH,body:{kind:'verify-reoon',label:'Verify emails (Reoon)',status:'running',total:emails.length,processed:0,started:now,message:'Submitting to Reoon…'},json:true}); jobId=j.id; }catch(e){}
sd.verifyJobId=jobId; sd.verifyTotal=emails.length; sd.verifyMap=map; sd.verifyPoll=0; sd.verifyWritten=0;
if(!emails.length){ if(jobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+jobId,headers:pbH,body:{status:'done',finished:now,processed:0,message:'Nothing to verify'},json:true}); }catch(e){} sd.verifyJobId=''; } return []; }
const name='leblovina-verify-'+now;
return [{json:{name, emails, truncated}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const r=$json||{};
const sd=$getWorkflowStaticData('global');
sd.verifyPoll=(sd.verifyPoll||0)+1;
const status=String(r.status||'');
const total=Number(r.count_total||sd.verifyTotal||0);
const checked=Number(r.count_checked||0);
if(sd.verifyJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.verifyJobId,headers:pbH,body:{processed:checked,total:total,message:'Verifying… '+checked+'/'+total},json:true}); }catch(e){} }
const hardFail=['file_not_found','file_loading_error'].includes(status);
const timedOut=sd.verifyPoll>180;
const done = status==='completed' || hardFail || timedOut;
return [{json:{done, failed:(hardFail||timedOut), status, results:(r.results||{})}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const sd=$getWorkflowStaticData('global');
const map=sd.verifyMap||{};
const results=($json && $json.results)||{};
const now=new Date().toISOString();
function mapStatus(r){ const s=((r&&r.status)||'').toString().toLowerCase();
  if(s==='safe'||s==='role_account') return 'verified';
  if(s==='catch_all') return 'catch_all';
  if(['invalid','disabled','disposable','spamtrap','inbox_full','undeliverable'].includes(s)) return 'undeliverable';
  if(s==='unknown' && r && r.mx_accepts_mail===true && r.is_valid_syntax!==false) return 'mx_only';
  return 'unknown'; }
const tasks=[];
for(const em of Object.keys(results)){ const id=map[String(em).toLowerCase()]; if(!id) continue; tasks.push({id, vs:mapStatus(results[em]||{})}); }
let written=0;
for(let i=0;i<tasks.length;i+=25){ await Promise.all(tasks.slice(i,i+25).map(t=>this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+t.id,headers:pbH,body:{verification_status:t.vs,verified_at:now},json:true}).then(()=>{written++;}).catch(()=>{}))); }
sd.verifyWritten=written;
return [{json:{written, failed: ($json && $json.failed)===true}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const now=new Date().toISOString();
try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="reoon"',perPage:1},headers:pbH,json:true}); const rec=s.items&&s.items[0]; if(rec){ const v=rec.value||{}; v.last_run=now; await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/settings/records/'+rec.id,headers:pbH,body:{value:v},json:true}); } }catch(e){}
const sd=$getWorkflowStaticData('global');
const written=sd.verifyWritten||0;
const failed=($json && $json.failed)===true;
if(sd.verifyJobId){ try{ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/job_runs/records/'+sd.verifyJobId,headers:pbH,body:{status:(failed?'error':'done'),finished:now,processed:written,message:(failed?'Reoon task did not complete (timed out)':('Verified '+written+' contact(s)'))},json:true}); }catch(e){} sd.verifyJobId=''; }
return [{json:{done:true, written}}];
